 1→import { useEffect } from "react";
 2→import { useOrganization } from "../../contexts/OrganizationContext";
 3→import { authClient } from "../../lib/auth-client";
 4→import { ensureChatwootLoaded, syncChatwootUser } from "../../lib/chatwoot";
 5→
 6→export function ChatwootBootstrap() {
 7→	const { data: session } = authClient.useSession();
 8→	const { activeOrg } = useOrganization();
 9→
10→	useEffect(() => {
11→		void ensureChatwootLoaded().catch(() => {
12→			// Keep the dashboard usable even if Chatwoot is unavailable.
13→		});
14→	}, []);
15→
16→	useEffect(() => {
17→		if (!session?.user) {
18→			return;
19→		}
20→
21→		const identifier =
22→			("id" in session.user && typeof session.user.id === "string"
23→				? session.user.id
24→				: undefined) ??
25→			("email" in session.user && typeof session.user.email === "string"
26→				? session.user.email
27→				: undefined);
28→
29→		if (!identifier) {
30→			return;
31→		}
32→
33→		void syncChatwootUser({
34→			identifier,
35→			email:
36→				"email" in session.user && typeof session.user.email === "string"
37→					? session.user.email
38→					: undefined,
39→			name: session.user.name,
40→			avatarUrl: session.user.image,
41→			organizationName: activeOrg?.name,
42→		});
43→	}, [activeOrg?.name, session?.user]);
44→
45→	return null;
46→}
