  1→import { join } from "node:path";
  2→import { getLogger, withContext } from "@logtape/logtape";
  3→import { onError } from "@orpc/server";
  4→import { RPCHandler } from "@orpc/server/fetch";
  5→import { user as userTable } from "@rudel/sql-schema";
  6→import { eq } from "drizzle-orm";
  7→import type { Session as AuthSession } from "./auth.js";
  8→import { createAuth } from "./auth.js";
  9→import { db } from "./db.js";
 10→import { setupLogging } from "./logging.js";
 11→import { router } from "./router.js";
 12→
 13→await setupLogging();
 14→
 15→const logger = getLogger(["rudel", "api", "http"]);
 16→type AuthUser = AuthSession["user"];
 17→
 18→const socialProviders: Record<
 19→	string,
 20→	{ clientId: string; clientSecret: string }
 21→> = {};
 22→if (process.env.GOOGLE_CLIENT_ID && process.env.GOOGLE_CLIENT_SECRET) {
 23→	socialProviders.google = {
 24→		clientId: process.env.GOOGLE_CLIENT_ID,
 25→		clientSecret: process.env.GOOGLE_CLIENT_SECRET,
 26→	};
 27→}
 28→if (process.env.GITHUB_CLIENT_ID && process.env.GITHUB_CLIENT_SECRET) {
 29→	socialProviders.github = {
 30→		clientId: process.env.GITHUB_CLIENT_ID,
 31→		clientSecret: process.env.GITHUB_CLIENT_SECRET,
 32→	};
 33→}
 34→
 35→const appURL = process.env.APP_URL ?? "http://localhost:4010";
 36→const ALLOWED_ORIGIN = process.env.ALLOWED_ORIGIN ?? "http://localhost:4011";
 37→const trustedOrigins = process.env.TRUSTED_ORIGINS
 38→	? process.env.TRUSTED_ORIGINS.split(",").map((o) => o.trim())
 39→	: [ALLOWED_ORIGIN];
 40→
 41→const auth = createAuth(db, {
 42→	appURL,
 43→	secret: process.env.BETTER_AUTH_SECRET,
 44→	socialProviders,
 45→	trustedOrigins,
 46→	cliDeviceVerificationUrl:
 47→		process.env.CLI_DEVICE_VERIFICATION_URL ?? `${ALLOWED_ORIGIN}/device`,
 48→	slackWebhookUrl: process.env.SLACK_WEBHOOK_URL,
 49→});
 50→
 51→const rpcHandler = new RPCHandler(router, {
 52→	interceptors: [
 53→		onError((error) => {
 54→			logger.error("RPC unhandled exception: {error} {stack}", {
 55→				error: String(error),
 56→				stack: error instanceof Error ? error.stack : undefined,
 57→			});
 58→		}),
 59→	],
 60→});
 61→
 62→const STATIC_DIR = join(
 63→	import.meta.dir,
 64→	"..",
 65→	process.env.STATIC_DIR ?? "public",
 66→);
 67→
 68→function getPublicRuntimeConfig() {
 69→	return {
 70→		CHATWOOT_BASE_URL:
 71→			process.env.VITE_CHATWOOT_BASE_URL ?? process.env.CHATWOOT_BASE_URL ?? "",
 72→		CHATWOOT_WEBSITE_TOKEN:
 73→			process.env.VITE_CHATWOOT_WEBSITE_TOKEN ??
 74→			process.env.CHATWOOT_WEBSITE_TOKEN ??
 75→			"",
 76→		CHATWOOT_ENABLED:
 77→			process.env.VITE_CHATWOOT_ENABLED ?? process.env.CHATWOOT_ENABLED ?? "",
 78→	};
 79→}
 80→
 81→function corsHeaders(origin: string | null): Record<string, string> {
 82→	if (origin !== ALLOWED_ORIGIN) return {};
 83→	return {
 84→		"Access-Control-Allow-Origin": ALLOWED_ORIGIN,
 85→		"Access-Control-Allow-Credentials": "true",
 86→		"Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
 87→		"Access-Control-Allow-Headers": "Content-Type, Authorization, X-API-Key",
 88→	};
 89→}
 90→
 91→const port = process.env.PORT ?? 4010;
 92→const MAX_REQUEST_BODY_BYTES = Number(
 93→	process.env.MAX_REQUEST_BODY_BYTES ?? 500 * 1024 * 1024, // 500 MB
 94→);
 95→
 96→const server = Bun.serve({
 97→	port,
 98→	async fetch(request) {
 99→		const origin = request.headers.get("Origin");
100→		const cors = corsHeaders(origin);
101→
102→		if (request.method === "OPTIONS") {
103→			return new Response(null, { status: 204, headers: cors });
104→		}
105→
106→		const contentLength = request.headers.get("Content-Length");
107→		if (contentLength && Number(contentLength) > MAX_REQUEST_BODY_BYTES) {
108→			return new Response(
109→				JSON.stringify({
110→					error: `Request body too large. Maximum size is ${Math.round(MAX_REQUEST_BODY_BYTES / (1024 * 1024))} MB.`,
111→				}),
112→				{
113→					status: 413,
114→					headers: { ...cors, "Content-Type": "application/json" },
115→				},
116→			);
117→		}
118→
119→		const url = new URL(request.url);
120→
121→		// Health check for Fly.io (must be GET-accessible)
122→		if (url.pathname === "/health") {
123→			return Response.json({ status: "ok", timestamp: Date.now() });
124→		}
125→
126→		const requestId = crypto.randomUUID();
127→		const start = performance.now();
128→
129→		return withContext(
130→			{ requestId, method: request.method, path: url.pathname },
131→			async () => {
132→				const response = await handleRequest(request, url, cors);
133→				const duration = Math.round(performance.now() - start);
134→				logger.info("{method} {path} {status} {duration}ms", {
135→					method: request.method,
136→					path: url.pathname,
137→					status: response.status,
138→					duration,
139→				});
140→				return response;
141→			},
142→		);
143→	},
144→});
145→
146→async function handleRequest(
147→	request: Request,
148→	url: URL,
149→	cors: Record<string, string>,
150→): Promise<Response> {
151→	// Defense in depth: block Better Auth's built-in org deletion route.
152→	// Rudel has its own guarded deletion path via the RPC router.
153→	if (url.pathname === "/api/auth/organization/delete") {
154→		return new Response("Not Found", { status: 404, headers: cors });
155→	}
156→	if (url.pathname.startsWith("/api/auth")) {
157→		const response = await auth.handler(request);
158→		for (const [key, value] of Object.entries(cors)) {
159→			response.headers.set(key, value);
160→		}
161→		return response;
162→	}
163→
164→	if (url.pathname === "/api/runtime-config") {
165→		return Response.json(getPublicRuntimeConfig(), {
166→			headers: {
167→				...cors,
168→				"Cache-Control": "no-store",
169→			},
170→		});
171→	}
172→
173→	const { matched, response } = await rpcHandler.handle(request, {
174→		prefix: "/rpc",
175→		context: await getContext(request),
176→	});
177→
178→	if (matched) {
179→		if (response.status >= 500) {
180→			const body = await response.clone().text();
181→			logger.error("RPC error on {path}: {status} {body}", {
182→				path: url.pathname,
183→				status: response.status,
184→				body,
185→			});
186→		}
187→		for (const [key, value] of Object.entries(cors)) {
188→			response.headers.set(key, value);
189→		}
190→		return response;
191→	}
192→
193→	// Static file serving (production: frontend assets)
194→	const filePath = join(STATIC_DIR, url.pathname);
195→	const file = Bun.file(filePath);
196→	if (await file.exists()) {
197→		return new Response(file);
198→	}
199→
200→	// SPA fallback: serve index.html for non-API routes
201→	const indexFile = Bun.file(join(STATIC_DIR, "index.html"));
202→	if (await indexFile.exists()) {
203→		return new Response(indexFile);
204→	}
205→
206→	// Dev mode: redirect to frontend dev server for non-API routes
207→	// (e.g., after OAuth callback redirects to APP_URL which has no SPA)
208→	if (ALLOWED_ORIGIN !== appURL) {
209→		return Response.redirect(
210→			`${ALLOWED_ORIGIN}${url.pathname}${url.search}`,
211→			302,
212→		);
213→	}
214→
215→	return new Response("Not found", { status: 404, headers: cors });
216→}
217→
218→async function getContext(request: Request) {
219→	const session = await auth.api.getSession({
220→		headers: request.headers,
221→	});
222→
223→	let apiKeyId: string | null = null;
224→	const apiKey =
225→		request.headers.get("x-api-key") ??
226→		request.headers.get("X-API-Key") ??
227→		null;
228→
229→	let apiKeyUser: AuthUser | null = null;
230→	if (apiKey) {
231→		try {
232→			const verification = await auth.api.verifyApiKey({
233→				body: {
234→					key: apiKey,
235→					permissions: { ingest: ["write"] },
236→				},
237→			});
238→
239→			if (verification.valid && verification.key) {
240→				const [foundUser] = await db
241→					.select({
242→						id: userTable.id,
243→						name: userTable.name,
244→						email: userTable.email,
245→						emailVerified: userTable.emailVerified,
246→						image: userTable.image,
247→						createdAt: userTable.createdAt,
248→						updatedAt: userTable.updatedAt,
249→					})
250→					.from(userTable)
251→					.where(eq(userTable.id, verification.key.referenceId))
252→					.limit(1);
253→
254→				if (foundUser) {
255→					apiKeyUser = foundUser as AuthUser;
256→					apiKeyId = verification.key.id;
257→				}
258→			}
259→		} catch {
260→			// Invalid API key is treated as unauthenticated for key-based auth.
261→		}
262→	}
263→
264→	return {
265→		user: session?.user ?? apiKeyUser ?? null,
266→		session: session?.session ?? null,
267→		apiKeyId,
268→	};
269→}
270→
271→logger.info("API server listening on http://localhost:{port}", {
272→	port: server.port,
273→});
