 1→import { organizationClient } from "better-auth/client/plugins";
 2→import { createAuthClient } from "better-auth/react";
 3→import { resetChatwoot } from "./chatwoot";
 4→import { queryClient } from "./query-client";
 5→
 6→export const authClient = createAuthClient({
 7→	baseURL: "",
 8→	plugins: [organizationClient()],
 9→});
10→
11→export async function signOut() {
12→	resetChatwoot();
13→	await authClient.signOut();
14→	queryClient.clear();
15→	localStorage.removeItem("dateRange");
16→	localStorage.removeItem("globalFilters");
17→	localStorage.removeItem("rudel:activeOrg");
18→	// Notify all better-auth signal atoms to trigger refetches,
19→	// clearing stale org data that /sign-out doesn't reset
20→	for (const key of Object.keys(authClient.$store.atoms)) {
21→		if (key.startsWith("$")) {
22→			authClient.$store.notify(key);
23→		}
24→	}
25→}
