 1→import { execFileSync } from "node:child_process";
 2→import { readFileSync } from "node:fs";
 3→import path from "node:path";
 4→import tailwindcss from "@tailwindcss/vite";
 5→import react from "@vitejs/plugin-react";
 6→import { defineConfig } from "vite";
 7→
 8→const { version } = JSON.parse(
 9→	readFileSync(new URL("./package.json", import.meta.url), "utf-8"),
10→) as { version: string };
11→
12→async function getLatestGitHubVersion() {
13→	const response = await fetch(
14→		"https://api.github.com/repos/obsessiondb/rudel/releases/latest",
15→		{
16→			headers: {
17→				Accept: "application/vnd.github+json",
18→				"User-Agent": "rudel-web-build",
19→			},
20→		},
21→	);
22→
23→	if (!response.ok) {
24→		throw new Error(`GitHub returned ${response.status}`);
25→	}
26→
27→	const data = (await response.json()) as { tag_name?: string };
28→
29→	if (!data.tag_name) {
30→		throw new Error("GitHub release response did not include a tag");
31→	}
32→
33→	return data.tag_name.replace(/^rudel@/, "");
34→}
35→
36→function getLatestLocalTagVersion() {
37→	const output = execFileSync("git", ["tag", "--sort=-version:refname"], {
38→		cwd: __dirname,
39→		encoding: "utf-8",
40→	});
41→
42→	const tag = output
43→		.split("\n")
44→		.map((line) => line.trim())
45→		.find(Boolean);
46→
47→	if (!tag) {
48→		throw new Error("No git tags found");
49→	}
50→
51→	return tag.replace(/^rudel@/, "");
52→}
53→
54→async function resolveAppVersion() {
55→	try {
56→		return await getLatestGitHubVersion();
57→	} catch {
58→		try {
59→			return getLatestLocalTagVersion();
60→		} catch {
61→			return version;
62→		}
63→	}
64→}
65→
66→export default defineConfig(async () => {
67→	const appVersion = await resolveAppVersion();
68→
69→	return {
70→		define: {
71→			__APP_VERSION__: JSON.stringify(appVersion),
72→		},
73→		plugins: [react(), tailwindcss()],
74→		server: {
75→			port: 4011,
76→			proxy: {
77→				"/api": "http://localhost:4010",
78→				"/rpc": "http://localhost:4010",
79→			},
80→		},
81→		resolve: {
82→			alias: {
83→				"@": path.resolve(__dirname, "./src"),
84→			},
85→		},
86→	};
87→});
