 25→type Page = "login" | "signup";
 26→
 27→function getDeviceUserCode(): string | null {
 28→	const params = new URLSearchParams(window.location.search);
 29→	return params.get("user_code");
 30→}
 31→
 32→function getValidRedirect(): string | null {
 33→	const params = new URLSearchParams(window.location.search);
 34→	const redirect = params.get("redirect");
 35→	if (!redirect) return null;
 36→	if (!redirect.startsWith("/") || redirect.startsWith("//")) return null;
 37→	return redirect;
 38→}
