 40→function App() {
 41→	const { data: session, isPending } = authClient.useSession();
 42→	const [page, setPage] = useState<Page>("login");
 43→	const [deviceProcessing, setDeviceProcessing] = useState(false);
 44→	const [deviceApproved, setDeviceApproved] = useState(false);
 45→	const [deviceDenied, setDeviceDenied] = useState(false);
 46→	const [deviceError, setDeviceError] = useState<string | null>(null);
 47→	const deviceUserCode = getDeviceUserCode();
 48→	const { resolvedTheme } = useTheme();
 49→	const logoSrc =
 50→		resolvedTheme === "dark" ? "/logo-light.svg" : "/logo-dark.svg";
 51→
 52→	async function submitDeviceDecision(action: "approve" | "deny") {
 53→		if (!deviceUserCode || deviceProcessing) return;
 54→		setDeviceProcessing(true);
 55→		setDeviceError(null);
 56→		try {
 57→			const response = await fetch(`/api/auth/device/${action}`, {
 58→				method: "POST",
 59→				credentials: "include",
 60→				headers: { "Content-Type": "application/json" },
 61→				body: JSON.stringify({ userCode: deviceUserCode }),
 62→			});
 63→			if (!response.ok) {
 64→				const body = (await response.json().catch(() => null)) as {
 65→					error_description?: string;
 66→					message?: string;
 67→				} | null;
 68→				throw new Error(
 69→					body?.error_description ??
 70→						body?.message ??
 71→						`Failed to ${action} CLI device login`,
 72→				);
 73→			}
 74→			if (action === "approve") {
 75→				setDeviceApproved(true);
 76→			} else {
 77→				setDeviceDenied(true);
 78→			}
 79→		} catch (err) {
 80→			setDeviceError(
 81→				err instanceof Error ? err.message : "Failed to process device login",
 82→			);
 83→		} finally {
 84→			setDeviceProcessing(false);
 85→		}
 86→	}
 87→
 88→	if (isPending) {
 89→		return (
 90→			<div className="flex min-h-screen items-center justify-center">
 91→				<p className="text-muted-foreground">Loading...</p>
 92→			</div>
 93→		);
 94→	}
 95→
 96→	if (deviceUserCode) {
 97→		if (deviceProcessing) {
 98→			return (
 99→				<div className="flex min-h-screen items-center justify-center">
100→					<p className="text-muted-foreground">Processing CLI login...</p>
101→				</div>
102→			);
103→		}
104→
105→		if (deviceApproved) {
106→			return (
107→				<div className="flex min-h-screen flex-col items-center justify-center gap-2">
108→					<p className="text-xl font-semibold">CLI login approved</p>
109→					<p className="text-muted-foreground">
110→						Return to your terminal to continue.
111→					</p>
112→				</div>
113→			);
114→		}
115→
116→		if (deviceDenied) {
117→			return (
118→				<div className="flex min-h-screen flex-col items-center justify-center gap-2">
119→					<p className="text-xl font-semibold">CLI login denied</p>
120→					<p className="text-muted-foreground">
121→						This authorization request was not approved.
122→					</p>
123→				</div>
124→			);
125→		}
126→
127→		if (!session) {
128→			return (
129→				<div className="flex min-h-screen flex-col items-center justify-center gap-6">
130→					<img src={logoSrc} alt="Rudel" className="h-10 w-10" />
131→					{page === "login" ? (
132→						<LoginForm onSwitchToSignup={() => setPage("signup")} />
133→					) : (
134→						<SignupForm onSwitchToLogin={() => setPage("login")} />
135→					)}
136→				</div>
137→			);
138→		}
139→
140→		return (
141→			<div className="flex min-h-screen flex-col items-center justify-center gap-4">
142→				<p className="text-xl font-semibold">Authorize CLI login</p>
143→				<p className="text-muted-foreground">
144→					User code: <span className="font-mono">{deviceUserCode}</span>
145→				</p>
146→				{deviceError ? (
147→					<p className="text-destructive">{deviceError}</p>
148→				) : (
149→					<p className="text-muted-foreground">
150→						Approve this request only if it was initiated by you from the CLI.
151→					</p>
152→				)}
153→				<div className="flex gap-2">
154→					<Button onClick={() => submitDeviceDecision("approve")}>
155→						Approve
156→					</Button>
157→					<Button
158→						variant="outline"
159→						onClick={() => submitDeviceDecision("deny")}
160→					>
161→						Deny
162→					</Button>
163→				</div>
164→			</div>
165→		);
166→	}
167→
168→	if (!session) {
169→		return (
170→			<div className="flex min-h-screen flex-col items-center justify-center gap-6">
171→				<img src={logoSrc} alt="Rudel" className="h-10 w-10" />
172→				{page === "login" ? (
173→					<LoginForm onSwitchToSignup={() => setPage("signup")} />
174→				) : (
175→					<SignupForm onSwitchToLogin={() => setPage("login")} />
176→				)}
177→			</div>
178→		);
179→	}
180→
181→	return (
182→		<Routes>
183→			<Route
184→				path="/"
185→				element={<Navigate to={getValidRedirect() || "/dashboard"} replace />}
186→			/>
187→			<Route
188→				path="/invitation/:invitationId"
189→				element={<AcceptInvitationPage />}
190→			/>
191→			<Route path="/dashboard" element={<DashboardLayout />}>
192→				<Route index element={<OverviewPage />} />
193→				<Route path="developers" element={<DevelopersListPage />} />
194→				<Route path="developers/:userId" element={<DeveloperDetailPage />} />
195→				<Route path="projects" element={<ProjectsListPage />} />
196→				<Route path="projects/:projectPath" element={<ProjectDetailPage />} />
197→				<Route path="sessions" element={<SessionsListPage />} />
198→				<Route path="sessions/:sessionId" element={<SessionDetailPage />} />
199→				<Route path="roi" element={<ROIPage />} />
200→				<Route path="errors" element={<ErrorsPage />} />
201→				<Route path="learnings" element={<LearningsPage />} />
202→				<Route path="profile" element={<ProfilePage />} />
203→				<Route path="invitations" element={<InvitationsPage />} />
204→				<Route path="organization" element={<OrganizationPage />} />
205→				<Route path="organization/new" element={<CreateOrgPage />} />
206→			</Route>
207→			<Route path="*" element={<Navigate to="/dashboard" replace />} />
208→		</Routes>
209→	);
210→}
211→
212→export default App;
