	email?: string;
	name?: string;
	avatar_url?: string;
	phone_number?: string;
	description?: string;
	company_name?: string;
};

type ChatwootAPI = {
	hasLoaded?: boolean;
	toggle: (state?: "open" | "close") => void;
	setUser: (identifier: string | number, user: ChatwootUser) => void;
	setLabel: (label: string) => void;
