	if (window.$chatwoot?.hasLoaded) {
		return;
	}

	if (loadPromise) {
		return loadPromise;
	}

	if (window.$chatwoot) {
		loadPromise = waitForChatwoot();
		return loadPromise.catch((error) => {
			loadPromise = null;
			throw error;
		});
	}

	loadPromise = new Promise<void>((resolve, reject) => {
		const existingScript = document.getElementById(
			SCRIPT_ID,
		) as HTMLScriptElement | null;

